 1	import * as React from 'react';
 2	
 3	import { V1GPU, V1HostDevice } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { VirtualizedTable } from '@openshift-console/dynamic-plugin-sdk';
 5	
 6	import useHardwareDevicesColumns from './hooks/useHardwareDevicesColumns';
 7	import HardwareDeviceRow from './HardwareDeviceRow';
 8	
 9	type HardwareDevicesListProps = {
10	  devices: V1GPU[] | V1HostDevice[];
11	  handleRemoveDevice: (device: V1GPU | V1HostDevice) => void;
12	};
13	
14	const HardwareDevicesList: React.FC<HardwareDevicesListProps> = ({
15	  devices,
16	  handleRemoveDevice,
17	}) => {
18	  const columns = useHardwareDevicesColumns();
19	  return (
20	    <VirtualizedTable
21	      columns={columns}
22	      data={devices || []}
23	      loaded
24	      loadError={false}
25	      Row={HardwareDeviceRow}
26	      rowData={{ handleRemoveDevice }}
27	      unfilteredData={devices || []}
28	    />
29	  );
30	};
31	
32	export default HardwareDevicesList;

